IF OBJECT_ID(N'POC.SAL_SOH',N'U') IS NULL CREATE TABLE POC.SAL_SOH (CD_FIRM varchar(10) NOT NULL,NO_SO varchar(30) NOT NULL,DT_SO date NOT NULL,CD_PARTNER varchar(20) NOT NULL,NM_PARTNER nvarchar(100) NOT NULL,ST_SO varchar(20) NOT NULL,CD_EMP varchar(20) NOT NULL,NM_EMP nvarchar(100) NULL,CD_CURRENCY varchar(10) NULL,RT_EXCHANGE decimal(19,6) NULL,DC_RMK nvarchar(1000) NOT NULL DEFAULT N'',MAIL_ID varchar(255) NULL,CD_USER_REG varchar(50) NOT NULL,TM_REG datetime2 NOT NULL,CD_USER_AMD varchar(50) NULL,TM_AMD datetime2 NULL,CONSTRAINT PK_SAL_SOH PRIMARY KEY(CD_FIRM,NO_SO),CONSTRAINT UQ_SAL_SOH_MAIL UNIQUE(MAIL_ID),CONSTRAINT FK_SAL_SOH_PARTNER FOREIGN KEY(CD_FIRM,CD_PARTNER) REFERENCES POC.MA_PARTNER(CD_FIRM,CD_PARTNER));
IF OBJECT_ID(N'POC.SAL_SOL',N'U') IS NULL CREATE TABLE POC.SAL_SOL (CD_FIRM varchar(10) NOT NULL,NO_SO varchar(30) NOT NULL,NO_LINE int NOT NULL,CD_ITEM varchar(30) NOT NULL,NM_ITEM nvarchar(100) NOT NULL,STND_ITEM nvarchar(100) NOT NULL,UNIT_ITEM varchar(10) NOT NULL,QT_SO decimal(19,4) NOT NULL,UM_SO decimal(19,4) NOT NULL,AM_SUPPLY decimal(19,4) NOT NULL,AM_VAT decimal(19,4) NOT NULL,AM_TOTAL decimal(19,4) NOT NULL,DT_DLV date NOT NULL,DC_RMK nvarchar(1000) NOT NULL DEFAULT N'',CD_USER_REG varchar(50) NOT NULL,TM_REG datetime2 NOT NULL,CD_USER_AMD varchar(50) NULL,TM_AMD datetime2 NULL,CONSTRAINT PK_SAL_SOL PRIMARY KEY(CD_FIRM,NO_SO,NO_LINE),CONSTRAINT FK_SAL_SOL_SOH FOREIGN KEY(CD_FIRM,NO_SO) REFERENCES POC.SAL_SOH(CD_FIRM,NO_SO),CONSTRAINT FK_SAL_SOL_ITEM FOREIGN KEY(CD_FIRM,CD_ITEM) REFERENCES POC.MA_ITEM(CD_FIRM,CD_ITEM));
IF NOT EXISTS(SELECT 1 FROM sys.indexes WHERE name=N'IX_SAL_SOH_SEARCH' AND object_id=OBJECT_ID(N'POC.SAL_SOH')) CREATE INDEX IX_SAL_SOH_SEARCH ON POC.SAL_SOH(CD_FIRM,DT_SO,CD_PARTNER,ST_SO);
IF EXISTS(SELECT 1 FROM sys.key_constraints WHERE parent_object_id=OBJECT_ID(N'POC.SAL_SOH') AND name=N'UQ_SAL_SOH_MAIL') ALTER TABLE POC.SAL_SOH DROP CONSTRAINT UQ_SAL_SOH_MAIL;
IF NOT EXISTS(SELECT 1 FROM sys.indexes WHERE name=N'UX_SAL_SOH_MAIL' AND object_id=OBJECT_ID(N'POC.SAL_SOH')) CREATE UNIQUE INDEX UX_SAL_SOH_MAIL ON POC.SAL_SOH(MAIL_ID) WHERE MAIL_ID IS NOT NULL;
